const { exec } = require('child_process');
const fs = require('fs');

function resizeImage(input, output, dimensions, effects) {
  const effectString = effects.join(' ');
  const command = `gm convert ${input} -resize ${dimensions} ${effectString} ${output}`;

  exec(command, (error, stdout, stderr) => {
    if (error) {
      console.error(`Error: ${error.message}`);
      return;
    }
    if (stderr) {
      console.error(`Stderr: ${stderr}`);
      return;
    }
    console.log('Image processed successfully');
  });
}

// Example usage
resizeImage('user_photo.jpg', 'thumb.jpg', '200x200', ['grayscale', 'enhance']);